-- TrinityCore-evry DB Rank 1: creature_template.faction name-remap UPDATEs
-- Build 12.0.7.68275 — exact unique Name_lang match → CreatureDifficulty.FactionTemplateID
-- Source: temp/faction-zero-name-remap-hits.csv (3407 rows)
-- UPDATE-only: sets faction on TDB entry; does NOT remap entry id to retail_creature_id

CREATE TEMPORARY TABLE `tmp_creature_faction_name_remap` (
  `entry` int unsigned NOT NULL,
  `faction` smallint unsigned NOT NULL,
  PRIMARY KEY (`entry`)
) ENGINE=Memory;








UPDATE `creature_template` ct
INNER JOIN `tmp_creature_faction_name_remap` src ON ct.`entry` = src.`entry`
SET ct.`faction` = src.`faction`;

DROP TEMPORARY TABLE `tmp_creature_faction_name_remap`;
